+            service_id: "svc".to_string(),
+            restart_policy: RestartPolicy::Permanent,
+            restart_budget: RestartBudget {
+                max_restarts: 10,
+                window_ticks: 100,
+            },
+            shutdown_order: 0,
+        });
+        sup.start_service("svc");
